<template>
  <div class="nextprev-navbar">
    <a class="prev-baihoc"> Bài trước </a>
    <a class="next-baihoc"> Bài sau </a>
  </div>
</template>

<script>
import baihocData from "@/assets/data/baihoc.json";

const urlParams = new URLSearchParams(window.location.search);

let idBaiHoc = urlParams.get("id");
if (idBaiHoc == null) idBaiHoc = -1;

export default {
  name: "NextPrevNavBar",
  mounted() {
    let prevBai = document.querySelector(".prev-baihoc");
    let nextBai = document.querySelector(".next-baihoc");
    baihocData.forEach((baihoc, index) => {
      if (baihoc.id == idBaiHoc) {
        let lastBaiHoc = baihocData[index - 1];
        let nextBaiHoc = baihocData[index + 1];

        let previousBaiLink = `${window.location.protocol}//${window.location.host}`;
        if (lastBaiHoc) {
          previousBaiLink += `/chi-tiet-bai-hoc.html?id=${lastBaiHoc.id}`;
        }
        prevBai.href = previousBaiLink;

        let nextBaiLink = `${window.location.protocol}//${window.location.host}`;
        if (nextBaiHoc) {
          nextBaiLink += `/chi-tiet-bai-hoc.html?id=${nextBaiHoc.id}`;
        }
        nextBai.href = nextBaiLink;
      }
    });
  },
};
</script>

<style>
.nextprev-navbar {
  display: flex;
  justify-content: space-between;
}

.next-baihoc, .prev-baihoc {
  text-decoration: none;
  color: #fff;
  padding: 15px 30px;
  border-radius: 15px;
}
.next-baihoc, .prev-baihoc:hover {
  background-color: #f76c6c;
  color: #f8e9a1;
}
.prev-baihoc, .next-baihoc:hover {
  color: #f76c6c;
  background-color: #f8e9a1;
}
</style>
