<template>
  <div class="card-program-header">
    <WaveContainer :title="'Bài học ' + baihoc.id" :description="baihoc.name" />
  </div>

  <div class="card-program-body">
    <iframe :src="'/quizes/' + embedlink" width="100%" height="800px"></iframe>
  </div>
  <NextPrevNavBar />

  <FoxNav />
</template>

<script>
import baihocData from "@/assets/data/baihoc.json";
import WaveContainer from "./WaveContainer.vue";
import FoxNav from './FoxNav.vue';
import NextPrevNavBar from './NextPrevNavBar.vue';

const urlParams = new URLSearchParams(window.location.search);
let idBaiHoc = urlParams.get("id");
if (idBaiHoc == null) idBaiHoc = -1;
let currentBaiHoc = baihocData.find((baihoc) => baihoc.id == idBaiHoc);
let contentLink = currentBaiHoc.contentdir;
export default {
  name: "CardBaiHoc",
  components: {
    WaveContainer,
    FoxNav,
    NextPrevNavBar,
  },
  props: {},
  data() {
    return {
      baihoc: currentBaiHoc,
      embedlink: contentLink,
    };
  },
};
</script>

