<template>
  <div class="fox-nav" @click="toggleNav()"></div>
  <div class="sidenav" v-if="sidenavShown">
    <a href="javascript:void(0)" class="closebtn" @click="closeNav()"
      >&times;</a
    >
    <div class="sidenav-body">
      <div class="sidenav-title">Chủ đề & Bài giảng</div>
      <div
        class="sidenav-part"
        v-for="chude in danhsachchude"
        v-bind:key="chude.id"
        v-bind:value="chude.id"
      >
        <span class="sidenav-chude">
          {{ `Chủ đề ${chude.id}: ${chude.name}` }}
        </span>
        <ul class="sidenav-content">
          <li
            v-for="baihoc in danhsachbaihoc.filter(
              (bh) => bh.idchude == chude.id
            )"
            v-bind:key="baihoc.id"
            v-bind:value="baihoc.id"
            :class="isActive(baihoc.id)"
          >
            <a :href="`/chi-tiet-bai-hoc.html?id=${baihoc.id}`">
              {{ `Bài ${baihoc.id}: ${baihoc.name}` }}
            </a>
          </li>
        </ul>
      </div>
    </div>
  </div>
</template>

<script>
import chudeData from "@/assets/data/chude.json";
import baihocData from "@/assets/data/baihoc.json";

const urlParams = new URLSearchParams(window.location.search);
// let idChuDe = urlParams.get("idChuDe");
// if (idChuDe == null) idChuDe = -1;

let idBaiHoc = urlParams.get("id");
if (idBaiHoc == null) idBaiHoc = -1;
console.log(idBaiHoc);

export default {
  name: "FoxNav",
  data() {
    return {
      sidenavShown: false,
      danhsachchude: chudeData,
      danhsachbaihoc: baihocData,
      currentBaihoc: idBaiHoc,
    };
  },
  methods: {
    closeNav() {
      this.sidenavShown = false;
    },
    openNav() {
      this.sidenavShown = true;
    },
    toggleNav() {
      this.sidenavShown = !this.sidenavShown;
    },
    isActive(id) {
      if (id == idBaiHoc) {
        return "activebaihoc";
      }
      return "";
    }
  },
  mounted() {
    document.body.addEventListener("click", (e) => {
      let foxnav = document.querySelector(".fox-nav");
      if (e.target != foxnav) this.closeNav();
    });
    let ifrbaihoc = document.querySelector("iframe"); 
    ifrbaihoc.contentWindow.addEventListener("click", () => {
      this.closeNav();
    });
  },
  computed: {
  }
};
</script>

